import{_ as i,o as n,c as o,ae as a}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Add Multiple Custom Domains","description":"","frontmatter":{"title":"Add Multiple Custom Domains","slug":"add-multiple-custom-domains"},"headers":[],"relativePath":"account-hub/add-multiple-custom-domains.md","filePath":"account-hub/add-multiple-custom-domains.md"}'),t={name:"account-hub/add-multiple-custom-domains.md"};function s(r,e,l,p,d,u){return n(),o("div",null,[...e[0]||(e[0]=[a('<p>You can now configure and use <strong>unlimited custom domains</strong> for your links if you have Branch Activation.</p><p>This update gives you the flexibility to manage multiple brands, streamline rebranding efforts, and create distinct user journeys for your web and app traffic.</p><p>To learn how to implement multiple custom domains, read our <a href="./basic-link-configuration.html#use-your-own-domain">Basic Link Configuration</a> article.</p><h2 id="what-s-new" tabindex="-1">What&#39;s new <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What&#39;s new&quot;">​</a></h2><ul><li><strong>Unlimited custom domains:</strong> Configure as many custom domains as you need within the dashboard. The process for adding a new domain remains the same.</li><li><strong>Select your domain during link creation:</strong> When creating a link in the Dashboard, you can now select your desired domain from a drop-down menu.</li><li><strong>Default API domain:</strong> For automated link creation, the API will use your default custom domain unless a different one is specified in the call.</li><li><strong>Enhanced flexibility for Activation Essentials:</strong> If you have the Activation Essentials package, you can now use your <code>app.link</code> domain in addition to any configured custom domains.</li></ul><h2 id="use-cases-and-benefits" tabindex="-1">Use cases and benefits <a class="header-anchor" href="#use-cases-and-benefits" aria-label="Permalink to &quot;Use cases and benefits&quot;">​</a></h2><p>This enhancement allows you to:</p><ul><li><strong>Manage multiple brands:</strong> Seamlessly manage link creation for different brands, business lines, or campaigns, each with its own unique domain.</li><li><strong>Execute smooth rebrands:</strong> Transition to a new brand domain without disrupting existing links or workflows.</li><li><strong>Separate web and app experiences:</strong> Dedicate specific domains for web-only traffic and others for app deep linking. This allows you to ensure web users are always directed to your mobile site and app users get the optimal deep linking experience.</li></ul><h2 id="implementation-options-for-activation" tabindex="-1">Implementation options for Activation <a class="header-anchor" href="#implementation-options-for-activation" aria-label="Permalink to &quot;Implementation options for Activation&quot;">​</a></h2><p>These options only apply if you have Branch Activation and have the ability to add multiple custom domains. For more information, read our <a href="./basic-link-configuration.html">Basic Link Configuration</a> article.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>You must complete the steps in the custom subdomain implementation instructions in our <a href="https://help.branch.io/docs/basic-link-configuration#use-a-custom-subdomain" target="_blank" rel="noreferrer">Basic Link Configuration</a> article for each custom domain that you add.</p></div><p><strong>Option 1: Single domain for web and app</strong></p><p>Use this approach to have a single custom domain to handle links that point to both web pages and in-app locations.</p><ul><li><p><strong>How it works</strong>: This configuration relies on Universal Links (iOS) and Android App Links to prioritize opening the app. If a user has your app and clicks a web link, the link will open in an in-app webview.</p></li><li><p><strong>Requirements</strong>: Your apps must have the <em>at least</em> the following SDK versions to support this option:</p><ul><li>iOS SDK ≥ 3.12.0</li><li>Android SDK ≥ 5.18.0</li></ul></li><li><p><strong>Pro:</strong> You can change a link&#39;s destination between a web page and an app view at any time without needing to generate a new link or update a QR code.</p></li><li><p><strong>Con</strong>: Requires having updated SDK versions to ensure a consistent user experience for all link types.</p></li></ul><p><strong>Option 2: Separate domains</strong></p><p>Use this approach to have separate dedicated domains for web links and app links, ensuring a clear separation of user experiences.</p><ul><li><p><strong>How it works</strong>: You configure at least two domains:</p><ul><li><strong>Web domain</strong>: A domain designated for web links. Links using this domain will never open the app and will always direct users to their mobile browser.</li><li><strong>App domain</strong>: A separate domain (for example, your default app.link domain or another custom domain) used exclusively for deep linking.</li></ul></li><li><p><strong>Requirements</strong>: No SDK update is required to implement this strategy, as the web domain does not interact with the SDK. However, you must integrate the Branch SDK if you want to deep link to locations in your app with app links.</p></li><li><p><strong>Pro</strong>: This method provides a predictable user experience by avoiding the in-app webview and does not require an SDK update to create web links.</p></li><li><p><strong>Con</strong>: A link&#39;s behavior is fixed to its domain. To switch a link&#39;s destination from a web page to an app view (or vice-versa), you must create an entirely new link using the appropriate domain.</p></li></ul>',17)])])}const h=i(t,[["render",s]]);export{m as __pageData,h as default};
